  return (
    <>
      <h1>Let's Learn React!</h1>
      {/* <Greet /> */}

      <img src={nature} 
      alt="Nature image" style={{width: "300px",borderRadius: "10px"}}/>

      <thead className='container'>Days
        <td>Sunday</td>
        <td>Monday</td>
        <td>Tuesday</td>
        <td>Thursday</td>
        <td>Friday</td>
        <td>Saturday</td>
      </thead>
      <tbody>
        <td>9-5</td>
        <td>9-5</td>
        <td>9-5</td>
        <td>9-5</td>
        <td>9-5</td>
        <td>9-5</td>
        <td>9-5</td>
      </tbody>
    </>

  );
}

export default App;
